import{a5 as t,e,f as o,V as d}from"./chunks/framework.CVnjVHOm.js";const h=JSON.parse('{"title":"Note 8","description":"","frontmatter":{},"headers":[],"relativePath":"css/No.8.md","filePath":"css/No.8.md"}'),c={name:"css/No.8.md"},r=d('<h1 id="note-8" tabindex="-1">Note 8 <a class="header-anchor" href="#note-8" aria-label="Permalink to &quot;Note 8&quot;">​</a></h1><h2 id="css3定位" tabindex="-1">CSS3定位 <a class="header-anchor" href="#css3定位" aria-label="Permalink to &quot;CSS3定位&quot;">​</a></h2><p><code>positon</code>属性指定了元素的定位类型（静态的，相对的，绝对的或固定的）,默认值：<code>static</code></p><p>JavaScript语法：<code>object.style.position=&quot;absolute&quot;</code></p><table><thead><tr><th style="text-align:left;">值</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">static</td><td style="text-align:left;"><strong>默认值。没有定位</strong>，元素<strong>出现在正常的流中</strong>（忽略 <code>top</code>, <code>bottom</code>, <code>left</code>, <code>right</code> 或者 <code>z-index</code> 声明）。</td></tr><tr><td style="text-align:left;">absolute</td><td style="text-align:left;">生成<strong>绝对定位</strong>的元素，<strong>相对于 <code>static</code> 定位以外的第一个父元素进行定位</strong>。<br>绝对定位的元素的位置<strong>相对于最近的已定位父元素，如果元素没有已定位的父元素，那么它的位置相对于<code>&lt;html&gt;</code></strong><br>元素的位置通过 <code>left</code>, <code>top</code>, <code>right</code> 以及 <code>bottom</code> 属性进行规定。能很准确的将元素移动到想要的位置。<br><strong>使元素的位置与文档流无关，因此不占据空间</strong>。</td></tr><tr><td style="text-align:left;">fixed</td><td style="text-align:left;">生成<strong>固定定位</strong>的元素，<strong>相对于浏览器窗口进行定位</strong>。<br>元素的位置通过 <code>left</code>, <code>top</code>, <code>right</code> 以及 <code>bottom</code> 属性进行规定。<br><strong><code>Fixed</code>定位使元素的位置与文档流无关，因此不占据空间</strong>。</td></tr><tr><td style="text-align:left;">relative</td><td style="text-align:left;">生成<strong>相对定位</strong>的元素，<strong>相对于元素默认的位置进行定位（相对其正常位置）</strong>。<br>因此，<code>left:20</code> 会向元素的 <code>LEFT</code> 位置添加 <code>20</code> 像素。同样通过<code>top</code>、<code>bottom</code>、<code>left</code>以及<code>bottom</code>来明确元素的位置。<br><strong>移动相对定位元素，但它原本所占的空间不会改变</strong>。</td></tr><tr><td style="text-align:left;">sticky</td><td style="text-align:left;">粘性定位，<strong>该定位基于用户滚动的位置</strong>。<br>它的行为就像 <code>position:relative;</code> 而当页面滚动超出目标区域时，它的表现就像 <code>position:fixed;</code>，它会固定在目标位置。<br>粘性定位的元素<strong>依赖于用户的滚动</strong>，在 <code>position:relative</code> 与 <code>position:fixed</code> 定位之间切换。<br>它的行为就像 <code>position:relative;</code> 而<strong>当页面滚动超出目标区域时，它的表现就像</strong> <code>position:fixed;</code>，它<strong>会固定在目标位置</strong>。<br>元素定位表现为<strong>在跨越特定阈值前为相对定位，之后为固定定位</strong>。<br>这个<strong>特定阈值指的是</strong> <code>top</code>, <code>right</code>, <code>bottom</code> 或 <code>left</code> 之一，换言之，指定 <code>top</code>, <code>right</code>, <code>bottom</code> 或 <code>left</code> 四个阈值其中之一，<strong>才可使粘性定位生效</strong>。否则其行为与相对定位相同。</td></tr><tr><td style="text-align:left;">inherit</td><td style="text-align:left;">规定应该<strong>从父元素继承 <code>position</code> 属性的值</strong>。</td></tr><tr><td style="text-align:left;">initial</td><td style="text-align:left;">设置该属性为默认值，详情查看 <code>CSS initial</code> 关键字。</td></tr></tbody></table>',5),s=[r];function n(l,i,a,g,f,p){return e(),o("div",null,s)}const x=t(c,[["render",n]]);export{h as __pageData,x as default};
